async def fetch(url: str):
    # simulated errors
    if "timeout" in url:
        raise TimeoutError(f"Timed out: {url}")
    if "conn" in url:
        raise ConnectionError(f"Cannot connect: {url}")

async def main():
    try:
        async with asyncio.TaskGroup() as tg:
            tg.create_task(fetch("http://timeout-host/api"))
            tg.create_task(fetch("http://conn-host/api"))
            tg.create_task(fetch("http://good-host/api"))
    except* TimeoutError as eg:
        print("Timeout errors — will retry later:")
        for e in eg.exceptions:
            print(f"  {e}")
    except* ConnectionError as eg:
