asyncio.run(main())

def process_batch(items: list[str]) -> list[str]:
    results = []
    errors = []
    for item in items:
        try:
            results.append(item.upper())  # could raise
        except ValueError as e:
            errors.append(e)
    if errors:
        raise ExceptionGroup("batch processing failed", errors)
    return results

try:
    process_batch(["ok", 123, "fine", None])
except* ValueError as eg:
    print(f"Skipped {len(eg.exceptions)} invalid items")

async def process_region(region: str, urls: list[str]):
    errors = []
    for url in urls:
        try:
            await fetch(url)
        except Exception as e:
            errors.append(e)
    if errors:
        raise ExceptionGroup(f"failures in {region}", errors)

async def main():
    try:
        async with asyncio.TaskGroup() as tg:
            tg.create_task(process_region("us-east", ["http://a", "http://b"]))
            tg.create_task(process_region("eu-west", ["http://c", "http://d"]))
    except* ConnectionError as eg:
        # eg.exceptions may contain nested ExceptionGroups — Python recurses
        print(f"Connection errors across all regions: {eg}")

import asyncio
from dataclasses import dataclass

class RateLimitError(Exception):
    pass

class AuthError(Exception):
    pass

@dataclass
class FetchResult:
    endpoint: str
    data: list[dict]

async def fetch_endpoint(endpoint: str) -> FetchResult:
    await asyncio.sleep(0.05)  # simulate I/O
    if endpoint == "/users":
        raise RateLimitError("Rate limit exceeded on /users")
    if endpoint == "/admin":
        raise AuthError("Token expired for /admin")
    return FetchResult(endpoint=endpoint, data=[{"id": 1}])

async def ingest_all(endpoints: list[str]) -> list[FetchResult]:
    results: list[FetchResult] = []
    tasks: dict[asyncio.Task, str] = {}

    async with asyncio.TaskGroup() as tg:
        for ep in endpoints:
            task = tg.create_task(fetch_endpoint(ep))
            tasks[task] = ep

    # If we reach here, all succeeded
    return [t.result() for t in tasks]

async def main():
    endpoints = ["/products", "/users", "/orders", "/admin", "/inventory"]
    try:
        results = await ingest_all(endpoints)
        print(f"All {len(results)} endpoints fetched successfully")
    except* RateLimitError as eg:
        print(f"Rate limited on {len(eg.exceptions)} endpoint(s) — scheduling retry")
        for e in eg.exceptions:
            print(f"  retry queued: {e}")
    except* AuthError as eg:
        print(f"Auth failure on {len(eg.exceptions)} endpoint(s) — refreshing tokens")
        for e in eg.exceptions:
            print(f"  token refresh needed: {e}")
    except* ConnectionError as eg:
        print(f"Network issues on {len(eg.exceptions)} endpoint(s) — will backoff")

asyncio.run(main())
